    /// A REAL BUG found+fixed (bug-hunt batch 147, PR-it539): an ai-fun TOOL's
    /// own panic, under `supervise ... restart on_failure`, produced a
    /// DIFFERENT message on native than on interp/KVM. `k_ai_tool_call`'s tool
    /// invocation (`k_call(...)`) let a real panic from the tool's body
    /// propagate straight past `k_ai_call`'s own "ai `name`: " wrapping to the
    /// OUTER supervision landing pad, unlike interp.rs/vm.rs's `ToolHost::
    /// call_tool`, which explicitly catches the tool's panic and converts it
    /// to `Err(msg)` first. Confirmed via a real CLI probe first: `kupl run`/
    /// `kupl run --vm` printed `[supervise] Worker6 restarted after panic: ai
    /// \`helper6\`: division by zero`; native printed the bare `division by
    /// zero`, missing the "ai `helper6`: " prefix entirely. Fixed by wrapping
    /// the tool call in its OWN setjmp/k_pad pad (the same pattern
    /// `k_dispatch` already uses for supervision), catching the panic and
    /// feeding it through `k_ai_err` before `k_ai_call` builds its wrapped
    /// message, instead of letting it reach the outer pad unwrapped.
    #[test]
    fn native_ai_fun_tool_panic_message_matches_interp_under_supervise() {
        if !cc_available() {
            return;
        }
        let src = "fun tool_x6() -> Int {\n    100 / 0\n}\n\
ai fun helper6() -> Str tools [tool_x6] {\n    intent \"h\"\n}\n\
component Worker6 {\n    intent \"w\"\n    in trigger: Int\n    out result: Str\n\
    on trigger(n) {\n        emit result(helper6())\n    }\n}\n\
component Driver6 {\n    intent \"d\"\n    out go: Int\n    on start {\n        emit go(1)\n    }\n}\n\
app Main6 {\n    intent \"m\"\n    let worker = Worker6()\n    let driver = Driver6()\n\
    wire driver.go -> worker.trigger\n    supervise worker restart on_failure\n}\n";
        let compiled = crate::run::compile(src).expect("program compiles");
        let module = crate::compile::compile_module(&compiled.program, &compiled.checked)
            .expect("module compiles");
        let c = super::emit_c(&module).expect("emit_c succeeds");
        let base = std::env::temp_dir().join(format!("kupl-cgen-aisup-{}", std::process::id()));
        let cpath = base.with_extension("c");
        let bin = base.with_extension("out");
        std::fs::write(&cpath, &c).unwrap();
        let status = std::process::Command::new(cc())
            .args(["-O2", "-o", bin.to_str().unwrap(), cpath.to_str().unwrap()])
            .status()
            .expect("cc runs");
        assert!(status.success(), "generated C must compile");
        let out = std::process::Command::new(&bin)
            .env("KUPL_AI_MOCK_HELPER6", "[{\"tool\":\"tool_x6\",\"input\":{}},{\"final\":\"done\"}]")
            .output()
            .expect("binary runs");
        let _ = std::fs::remove_file(&cpath);
        let _ = std::fs::remove_file(&bin);
        let stderr = String::from_utf8_lossy(&out.stderr);
        assert!(
            stderr.contains("[supervise] Worker6 restarted after panic: ai `helper6`: division by zero"),
            "native must wrap the tool's panic with the SAME \"ai `name`: \" prefix as interp/KVM: {stderr:?}"
        );
        assert!(out.status.success(), "supervision must catch the tool panic, not exit non-zero: {out:?}");
    }

    /// A REAL cross-engine divergence found+fixed (production-hardening
    /// PR-it756, the SAME wrapping site as the test above, a different
    /// trigger): a self-referential/mutually-recursive `ai fun` <-> tool
    /// call chain re-enters `k_ai_call` at every nested level on the way
    /// back up the unwind, and (before this fix) each level's OWN
    /// `k_ai_call` re-wrapped the SAME error with another `"ai \`name\`: "`
    /// prefix -- at the time of this fix, bounded/truncated by `k_ai_err`/
    /// `b`'s then-fixed buffer sizes (unlike interp/vm's unbounded Rust
    /// `String`, which grew to ~65KB before the SAME sibling bug was fixed
    /// there; `k_ai_err`/`b` later became dynamically growable too, at
    /// PR-it936, but the skip-re-wrap fix below is what actually prevents
    /// the accumulation, independent of buffer size), but still a genuine
    /// cross-engine byte-identity divergence: interp/vm (post-fix) report
    /// the single-wrapped `"ai \`call_a\`: stack overflow (10000 frames)"`,
    /// but native (pre-fix) reported a ~276-byte message of roughly 20
    /// repeated `"ai \`call_a\`: "` prefixes before truncating. Confirmed
    /// live via a real compile+run BEFORE this fix, then fixed by mirroring
    /// `ai.rs::ai_call`'s exact fix: skip re-wrapping when `k_ai_err`
    /// already starts with `"ai \`"` (the only place this runtime ever
    /// produces that prefix, so it unambiguously means "already wrapped by
    /// a deeper `k_ai_call` frame").
    #[test]
    fn native_self_referential_ai_fun_tool_recursion_matches_interp_message() {
        if !cc_available() {
            return;
        }
        let src = "ai fun call_a7(x: Int) -> Int tools [helper_a7] {\n    intent \"loop\"\n}\n\
                   fun helper_a7(x: Int) -> Int {\n    call_a7(x)\n}\n\
                   fun main() uses io {\n    print(call_a7(1))\n}\n";
        let compiled = crate::run::compile(src).expect("program compiles");
        let module = crate::compile::compile_module(&compiled.program, &compiled.checked)
            .expect("module compiles");
        let c = super::emit_c(&module).expect("emit_c succeeds");
        let base = std::env::temp_dir().join(format!("kupl-cgen-airec-{}", std::process::id()));
        let cpath = base.with_extension("c");
        let bin = base.with_extension("out");
        std::fs::write(&cpath, &c).unwrap();
        let status = std::process::Command::new(cc())
            .args(["-O2", "-o", bin.to_str().unwrap(), cpath.to_str().unwrap()])
            .status()
            .expect("cc runs");
        assert!(status.success(), "generated C must compile");
        let out = std::process::Command::new(&bin)
            .env("KUPL_AI_MOCK_CALL_A7", "[{\"tool\":\"helper_a7\",\"input\":{\"x\":1}}]")
            .output()
            .expect("binary runs");
        let _ = std::fs::remove_file(&cpath);
        let _ = std::fs::remove_file(&bin);
        let stderr = String::from_utf8_lossy(&out.stderr);
        assert_eq!(
            stderr.trim(),
            "panic: ai `call_a7`: stack overflow (10000 frames)",
            "native must match interp/vm's SINGLE-wrapped message, not one prefix per recursion level: {stderr:?}"
        );
    }

    /// A REAL, LIVE-CONFIRMED silent-wrong-value bug found+fixed (production-
    /// hardening PR-it1052): native shares compile.rs's compiled bytecode
    /// with the VM (`kupl native` compiles the SAME `Module`/`Chunk`/`Op`
    /// sequence `compile_module` emits for `kupl run --vm`), so the fast-
    /// path fix in `compile.rs`'s `Stmt::Assign` handling (see
    /// `vm.rs::diff_self_mutating_fast_path_local_var_uses_the_pre_rhs_
    /// value_not_a_post_side_effect_one` for the full writeup) benefits
    /// native identically -- confirmed live BEFORE this fix: this exact
    /// program printed `100`/`[9, 9, 5]` on `kupl native`, matching `kupl
    /// run --vm`'s own wrong output, both diverging from `kupl run`'s
    /// correct `6`/`[1, 2, 3, 5]`.
    #[test]
    fn native_self_mutating_fast_path_local_var_uses_the_pre_rhs_value_not_a_post_side_effect_one() {
        if !cc_available() {
            return;
        }
        let src = "fun main() uses io {\n    \
                   var x = 5\n    x = x + { x = 99\n        1 }\n    print(\"{x}\")\n    \
                   var xs = [1, 2, 3]\n    xs = xs.push({ xs = [9, 9]\n        5 })\n    print(\"{xs}\")\n}\n";
        assert_eq!(native_main_stdout(src, "selfmutfastpath"), "6\n[1, 2, 3, 5]\n");
    }

