    /// A REAL cross-engine divergence found+fixed (production-hardening
    /// PR-it936): `k_ai_err` -- the buffer `k_ai_convert`/`k_ai_from_json`
    /// build every AI-shape-mismatch/JSON-parse-error message into -- used
    /// to be a fixed `char[256]`, silently TRUNCATING any message longer
    /// than 255 bytes, unlike ai.rs's own unbounded Rust `String`
    /// (`format!("expected {}, model returned {}", ...)`, ai.rs:396).
    /// Confirmed live via a 391-byte JSON-array mock response on a plain
    /// (non-`wraps_result`) `ai fun`: interp/vm panicked with the FULL
    /// message, native cut it off mid-number with no indication of
    /// truncation. Now a growable `KBuf`, matching ai.rs exactly.
    #[test]
    fn native_ai_fun_panic_message_is_not_truncated_by_a_fixed_size_buffer() {
        if !cc_available() {
            return;
        }
        let src = "ai fun classify(text: Str) -> Int {\n    intent \"x\"\n}\n\
                   fun main() uses io {\n    print(classify(\"x\"))\n}\n";
        // A JSON array long enough to overflow the OLD 256-byte fixed buffer
        // once echoed back inside "expected Int, model returned " -- the
        // WHOLE array, including its final element, must survive intact.
        let items: Vec<String> = (0..100).map(|i| i.to_string()).collect();
        let mock = format!("[{}]", items.join(","));
        let compiled = crate::run::compile(src).expect("program compiles");
        let module = crate::compile::compile_module(&compiled.program, &compiled.checked)
            .expect("module compiles");
        let c = super::emit_c(&module).expect("emit_c succeeds");
        let base = std::env::temp_dir().join(format!("kupl-cgen-aitrunc-{}", std::process::id()));
        let cpath = base.with_extension("c");
        let bin = base.with_extension("out");
        std::fs::write(&cpath, &c).unwrap();
        let status = std::process::Command::new(cc())
            .args(["-O2", "-o", bin.to_str().unwrap(), cpath.to_str().unwrap()])
            .status()
            .expect("cc runs");
        assert!(status.success(), "generated C must compile");
        let out = std::process::Command::new(&bin)
            .env("KUPL_AI_MOCK_CLASSIFY", &mock)
            .output()
            .expect("binary runs");
        let _ = std::fs::remove_file(&cpath);
        let _ = std::fs::remove_file(&bin);
        let stderr = String::from_utf8_lossy(&out.stderr);
        assert!(
            stderr.contains(&format!("expected Int, model returned {mock}")),
            "the FULL untruncated mock response must appear in the panic message, \
             not cut off mid-content (the old 256-byte k_ai_err buffer used to \
             truncate this): {stderr:?}"
        );
    }

    /// A REAL cross-engine divergence found+fixed (production-hardening
    /// PR-it936, the SAME fixed-buffer-truncation bug as the sibling test
    /// above, but reached through the `wraps_result` (`-> Result[T, Str]`)
    /// path instead of a panic): `k_ai_call`'s
    /// `k_err(k_str(k_strdup(k_ai_err)))` built a genuine `Err(Str)` VALUE
    /// directly from the (formerly fixed-size) buffer -- a KUPL program can
    /// pattern-match/print/compare that value, so truncation there was
    /// silent VALUE corruption, not just truncated crash output. Also
    /// confirmed live that truncation could land mid-UTF-8-multibyte-
    /// character (a large response padded with a repeated multi-byte
    /// character): native's own UTF-8 validation substituted U+FFFD rather
    /// than crashing or corrupting memory, but the STRING CONTENT still
    /// diverged from interp/vm's full, valid text either way. Now
    /// byte-identical to interp/vm (the exact char count -- 3 chars/euro
    /// sign literal, wrapped in a 3-char JSON `["..."]` envelope, times 300
    /// repetitions, plus the "expected Int, model returned " prefix --
    /// pins the full content, not just "didn't crash").
    #[test]
    fn native_ai_fun_result_err_value_is_not_truncated_or_utf8_corrupted() {
        if !cc_available() {
            return;
        }
        let src = "ai fun classify(text: Str) -> Result[Int, Str] {\n    intent \"x\"\n}\n\
                   fun main() uses io {\n    \
                   match classify(\"x\") {\n        \
                   Ok(v) => print(\"ok\")\n        \
                   Err(e) => print(\"{e.len()}|{e}\")\n    \
                   }\n}\n";
        // 300 repeated 3-byte UTF-8 characters ('€', U+20AC) inside a JSON
        // string -- long enough that the old 256-byte buffer's truncation
        // point landed mid-character for the overwhelming majority of
        // possible prefix lengths (confirmed live: it did).
        let euro_run = "\u{20AC}".repeat(300);
        let mock = format!("[\"{euro_run}\"]");
        let expected_msg = format!("expected Int, model returned {mock}");
        let expected_len = expected_msg.chars().count();
        let out = native_main_stdout_env(src, "aireserr", &[("KUPL_AI_MOCK_CLASSIFY", &mock)]);
        assert_eq!(
            out.trim(),
            format!("{expected_len}|{expected_msg}"),
            "the Err(Str) VALUE must carry the FULL, byte-identical, valid-UTF-8 \
             message -- not truncated, and not corrupted with a mid-character U+FFFD \
             replacement (both observed with the old fixed-size k_ai_err buffer)"
        );
    }

    /// A multi-component app (children + wires + emit) compiles to native and
    /// matches the interpreter, exercising the message queue and drain.
    #[test]
    fn native_multi_component_wires() {
        if !cc_available() {
            return;
        }
        // Driver emits three ticks into Sink via a wire; Sink accumulates + prints.
        let src = "component Sink {\n    in tick: Int\n    state total: Int = 0\n    \
                   on tick(n) {\n        total = total + n\n        print(\"total={total}\")\n    }\n}\n\
                   component Driver {\n    out pulse: Int\n    \
                   on start {\n        emit pulse(10)\n        emit pulse(20)\n        emit pulse(30)\n    }\n}\n\
                   app A {\n    let sink = Sink()\n    let driver = Driver()\n    \
                   wire driver.pulse -> sink.tick\n}\n";
        let compiled = crate::run::compile(src).expect("program compiles");
        let module = crate::compile::compile_module(&compiled.program, &compiled.checked)
            .expect("module compiles");
        let c = super::emit_c(&module).expect("multi-component app compiles to C");
        let base = std::env::temp_dir().join(format!("kupl-cgen-mc-{}", std::process::id()));
        let cpath = base.with_extension("c");
        let bin = base.with_extension("out");
        std::fs::write(&cpath, &c).unwrap();
        let status = std::process::Command::new(cc())
            .args(["-O2", "-o", bin.to_str().unwrap(), cpath.to_str().unwrap()])
            .status()
            .expect("cc runs");
        assert!(status.success(), "generated C must compile");
        let out = std::process::Command::new(&bin).output().expect("binary runs");
        assert_eq!(String::from_utf8_lossy(&out.stdout), "total=10\ntotal=30\ntotal=60\n");
        let _ = std::fs::remove_file(&cpath);
        let _ = std::fs::remove_file(&bin);
    }

    /// Compile `src` (a component app) to native, run it, and return stdout.
    #[cfg(test)]
    fn native_stdout(src: &str, tag: &str) -> String {
        let compiled = crate::run::compile(src).expect("program compiles");
        let module = crate::compile::compile_module(&compiled.program, &compiled.checked)
            .expect("module compiles");
        let c = super::emit_c(&module).expect("emit_c succeeds");
        let base = std::env::temp_dir().join(format!("kupl-cgen-{tag}-{}", std::process::id()));
        let cpath = base.with_extension("c");
        let bin = base.with_extension("out");
        std::fs::write(&cpath, &c).unwrap();
        let status = std::process::Command::new(cc())
            .args(["-O2", "-o", bin.to_str().unwrap(), cpath.to_str().unwrap()])
            .status()
            .expect("cc runs");
        assert!(status.success(), "generated C must compile");
        let out = std::process::Command::new(&bin).output().expect("binary runs");
        let _ = std::fs::remove_file(&cpath);
        let _ = std::fs::remove_file(&bin);
        String::from_utf8_lossy(&out.stdout).into_owned()
    }

    /// Native component STATE fields and cross-component `emit`/`wire` messages carry
    /// BigInt/Rational/sized-int values correctly -- a genuinely untested combination
    /// (bug-hunt batch 159, PR-it551): every prior native component test used only Int
    /// state/messages, and every prior BigInt/Rational/sized-int test used only local
    /// variables or List elements, never a component's heap-allocated instance state or a
    /// message payload crossing a wire (which native compiles to a distinct C code path --
    /// struct-field storage and an emit/dispatch queue -- from a local C variable). CLEAN:
    /// no bug found; BigInt/Rational's boxed representation survives both state mutation
    /// across a loop and copying across the wire dispatch queue correctly.
    #[test]
    fn native_component_state_and_wires_support_bigint_rational_sized_int() {
        if !cc_available() {
            return;
        }
        let state_src = "app Ticker {\n    state total: BigInt = big(0)\n    state r: Rational = rat(0, 1)\n    state sizedvals: List[i32] = []\n    \
                   on start {\n        var i = 0\n        while i < 5 {\n            total = total + big(i)\n            r = r + rat(1, i + 1)\n            sizedvals = sizedvals.push(i.to_i32())\n            i = i + 1\n        }\n        \
                   print(\"total = {total}\")\n        print(\"r = {r}\")\n        print(\"sorted = {sizedvals.sort()}\")\n}\n}\n";
        assert_eq!(
            native_stdout(state_src, "compnumstate"),
            "total = 10\nr = 137/60\nsorted = [0, 1, 2, 3, 4]\n"
        );
        let wire_src = "component Source {\n    out total: BigInt\n    out frac: Rational\n    \
                   on start {\n        emit total(big(42))\n        emit frac(rat(3, 4))\n    }\n}\n\
                   component Sink {\n    in total: BigInt\n    in frac: Rational\n    \
                   on total(x) {\n        print(\"total = {x * big(2)}\")\n    }\n    \
                   on frac(y) {\n        print(\"frac = {y * rat(2, 1)}\")\n    }\n}\n\
                   app Main {\n    let src = Source()\n    let sink = Sink()\n    \
                   wire src.total -> sink.total\n    wire src.frac -> sink.frac\n}\n";
        assert_eq!(native_stdout(wire_src, "compnumwire"), "total = 84\nfrac = 3/2\n");
    }

    /// A REAL, live-confirmed silent-wrong-answer bug found+fixed (production-
    /// hardening PR-it991, mirroring the identical interp.rs/vm.rs fixes --
    /// an Explore survey finding): `k_expose_call` (an ORDINARY exposed-method
    /// call, as opposed to a port/timer-triggered handler dispatched via
    /// `k_dispatch`, which already calls `k_drain()`) never drained the
    /// message queue after running the called chunk, even though `emit` is
    /// legal inside ANY component method, not just an `on` handler. A
    /// component whose exposed method emits (`Trigger991.press()` below)
    /// silently queued the message and never delivered it to its wired
    /// sibling -- confirmed live BEFORE this fix: `peek()` printed `0`
    /// instead of `7` on `kupl native` (matching the SAME bug independently
    /// confirmed on interp/KVM, not a cross-engine divergence -- all three
    /// engines shared this bug identically).
    #[test]
    fn native_an_ordinary_exposed_method_call_that_emits_actually_delivers_the_message() {
        if !cc_available() {
            return;
        }
        let src = "component Counter991 {\n    state total: Int = 0\n    in bump: Int\n    \
                   on bump(n) { total = total + n }\n    expose fun read() -> Int { total }\n}\n\
                   component Trigger991 {\n    out fired: Int\n    expose fun press() { emit fired(7) }\n}\n\
                   component Rig991 {\n    let t = Trigger991()\n    let c = Counter991()\n    \
                   wire t.fired -> c.bump\n    expose fun poke() { t.press() }\n    \
                   expose fun peek() -> Int { c.read() }\n}\n\
                   app Main991 {\n    let r = Rig991()\n    on start {\n        r.poke()\n        print(\"{r.peek()}\")\n    }\n}\n";
        assert_eq!(
            native_stdout(src, "exposeemit991"),
            "7\n",
            "an exposed method's `emit` must actually reach its wired sibling on native too, not sit undelivered in the queue"
        );
    }

