    /// `Set.intersect`/`difference`/`symmetric_difference`/`is_subset`/
    /// `is_superset`'s own O((n+m) log n) fast paths (production-hardening
    /// PR-it829, the SEVENTH through ELEVENTH instances of the naive-O(n^2)-
    /// collection-algorithm bug class, follow-ups to PR-it828's `union`):
    /// confirms BigInt/SizedInt/F32 coverage, Rational exclusion (via the
    /// naive fallback), NaN-collapsing, and self-order preservation.
    #[test]
    fn native_set_algebra_fast_paths_cover_bigint_sizedint_f32_and_exclude_rational() {
        if !cc_available() {
            return;
        }
        let src = "fun main() uses io {\n    \
                   let ab = Set([big(3), big(1), big(4)])\n    let bb = Set([big(4), big(1)])\n    \
                   let ai = Set([5i32, 3i32])\n    let bi = Set([3i32, 1i32])\n    \
                   let nan = 0.0f32 / 0.0f32\n    \
                   let af = Set([1.0f32, nan, 2.0f32])\n    let bf = Set([nan, 3.0f32])\n    \
                   let ar = Set([rat(1, 2), rat(1, 3)])\n    let br = Set([rat(1, 3), rat(2, 3)])\n    \
                   let empty: Set[Int] = Set([])\n    let ie = Set([1, 2, 3])\n    \
                   print(\"{ab.intersect(bb)}|{ab.difference(bb)}|{ab.symmetric_difference(bb)}|{ab.is_subset(bb)}|{bb.is_subset(ab)}\")\n    \
                   print(\"{ai.intersect(bi).len()}|{ai.difference(bi).len()}|{ai.symmetric_difference(bi).len()}\")\n    \
                   print(\"{af.intersect(bf)}|{af.difference(bf)}|{af.symmetric_difference(bf)}\")\n    \
                   print(\"{ar.intersect(br)}|{ar.difference(br)}|{ar.is_superset(br)}\")\n    \
                   print(\"{empty.is_subset(ie)}|{ie.is_subset(empty)}|{ie.is_superset(empty)}|{ie.intersect(ie).len()}|{ie.difference(ie).len()}\")\n}\n";
        let out = native_main_stdout(src, "set_algebra_bigint_sizedint_f32_rational");
        assert_eq!(
            out.trim(),
            "Set{1, 4}|Set{3}|Set{3}|false|true\n\
             1|1|2\n\
             Set{NaN}|Set{1.0, 2.0}|Set{1.0, 2.0, 3.0}\n\
             Set{1/3}|Set{1/2}|false\n\
             true|false|true|3|0"
        );
    }

    /// Native `.sort()` correctly sorts a large (30,000-element) reverse-sorted list --
    /// exercises the qsort-based implementation's heap allocation/comparator at a size
    /// where a subtle indexing bug could plausibly only show up at scale (production-
    /// hardening PR-it818, replacing a hand-rolled O(n^2) insertion sort with a stable
    /// `qsort` + original-index tiebreak, mirroring this file's own `.sort_by()`). The
    /// LATENCY improvement itself (~3.0s insertion sort -> ~0.2s qsort on this input,
    /// confirmed live via revert-and-verify, matching interp.rs/vm.rs's shared O(n log n)
    /// Rust `slice::sort_by`) is intentionally NOT asserted here as a wall-clock threshold:
    /// under full-suite parallel `cargo test` CPU contention (many concurrent `cc`-spawning
    /// native tests), a fixed-threshold timing assertion was confirmed LIVE to be flaky --
    /// it passed reliably in isolation (~0.7s) but failed under full-suite contention,
    /// which inflates wall-clock time for BOTH the fast and slow algorithm unpredictably.
    #[test]
    fn native_sort_of_a_large_reverse_sorted_list_is_correct() {
        if !cc_available() {
            return;
        }
        let src = "fun main() uses io {\n    var xs = []\n    var i = 0\n    let n = 30000\n    \
                   while i < n {\n        xs = xs.push(n - i)\n        i = i + 1\n    }\n    \
                   let sorted = xs.sort()\n    \
                   print(\"len={sorted.len()} first={sorted.first().unwrap_or(0 - 1)} last={sorted.last().unwrap_or(0 - 1)}\")\n}\n";
        assert_eq!(
            native_main_stdout(src, "sortlarge").trim(),
            "len=30000 first=1 last=30000"
        );
    }

    /// The `m = m.insert(k, v)`/`s = s.insert(v)` self-rebind in-place fast paths
    /// (`k_map_insert_inplace`/`k_set_insert_inplace`) are a SEPARATE code path from
    /// the general `.insert` method dispatch, and were fixed to use `k_key_eq`
    /// alongside it in PR-it691 -- unlike interp/KVM, where the equivalent fast
    /// paths (`Env::insert_map_in_place`/`insert_set_in_place` in value.rs, and
    /// vm.rs's own inline copy) were MISSED by it691 and only fixed in the
    /// follow-up PR-it692. This test locks native's (already-correct) behavior
    /// permanently, matching the interp/KVM regression test added alongside it692's
    /// fix (`diff_map_set_self_insert_in_place_nan_key_identity`).
    #[test]
    fn native_map_set_self_insert_in_place_nan_key_identity() {
        if !cc_available() {
            return;
        }
        let src = "fun main() uses io {\n    let nan = 0.0 / 0.0\n    \
                   var m = Map()\n    m = m.insert(nan, 1)\n    m = m.insert(nan, 2)\n    \
                   var s = Set()\n    s = s.insert(nan)\n    s = s.insert(nan)\n    \
                   print(\"{m.get(nan)}|{m.len()}|{s.len()}|{s.contains(nan)}\")\n}\n";
        assert_eq!(
            native_main_stdout(src, "naninplace").trim(),
            "Some(2)|1|1|true"
        );
    }

    /// Native float comparison is IEEE-correct for NaN (`<=`/`>=` against NaN are false, not
    /// true) — a regression guard for PR-it148: k_cmp used to collapse NaN's unordered
    /// result into a 3-way 0 (looks equal), making `nan <= nan` wrongly true. Now floats
    /// compare with the C operators directly, matching interp/KVM.
    #[test]
    fn native_nan_comparison_is_ieee_correct() {
        if !cc_available() {
            return;
        }
        let src = "fun main() uses io {\n    let nan = 0.0 / 0.0\n    \
                   print(\"{nan == nan}|{nan != nan}|{nan < 1.0}|{nan <= nan}|{nan >= nan}|{1.0 < nan}|{1.5 < 2.5}|{2.5 <= 2.5}|{3.0 >= 2.0}\")\n}\n";
        assert_eq!(native_main_stdout(src, "nancmp").trim(), "false|true|false|false|false|false|true|true|true");
    }

    /// Native's manual float formatter matches interp/KVM at the extremes: special
    /// values, IEEE semantics, negative zero, and exact round-trips of huge/tiny magnitudes.
    #[test]
