    /// Native parse_iso rejects an impossible day-of-month (leap-year aware), matching
    /// the interpreter (PR-it111).
    #[test]
    fn native_parse_iso_rejects_impossible_dates() {
        if !cc_available() {
            return;
        }
        let src = "fun main() uses io {\n    \
                   print(\"{parse_iso(\"2023-02-29\").is_ok()}|{parse_iso(\"2024-02-29\").is_ok()}|\
                   {parse_iso(\"1900-02-29\").is_ok()}|{parse_iso(\"2000-02-29\").is_ok()}|\
                   {parse_iso(\"2024-04-31\").is_ok()}|{parse_iso(\"2024-04-30\").is_ok()}\")\n}\n";
        assert_eq!(native_main_stdout(src, "iso").trim(), "false|true|false|true|false|true");
    }

    /// A REAL bug found+fixed (production-hardening PR-it880, mirrors
    /// time.rs::parse_iso's IDENTICAL fix -- confirmed a SHARED bug across all
    /// three engines before this fix, not a divergence between them): an
    /// explicit `T`/space separator with NOTHING after it (e.g.
    /// "2024-01-01T") set native's `time` pointer at the string's own NUL
    /// terminator, indistinguishable from `time == 0` (no separator, i.e. a
    /// genuinely valid date-only string) by `if (time && *time)` -- so ALL
    /// time validation was silently skipped and defaulted to midnight, the
    /// SAME timestamp as the genuinely valid date-only string. Confirmed live
    /// on native BEFORE this fix: `parse_iso("2024-01-01T").is_ok()` was
    /// `true`, identical to `parse_iso("2024-01-01").is_ok()`.
    #[test]
    fn native_parse_iso_rejects_a_trailing_separator_with_nothing_after_it() {
        if !cc_available() {
            return;
        }
        let src = "fun main() uses io {\n    \
                   print(\"{parse_iso(\"2024-01-01T\").is_ok()}|{parse_iso(\"2024-01-01T   \").is_ok()}|\
                   {parse_iso(\"2024-01-01TZ\").is_ok()}|{parse_iso(\"2024-01-01\").is_ok()}|\
                   {parse_iso(\"2024-01-01T12\").is_ok()}|{parse_iso(\"2024-01-01T00:00:00\").is_ok()}\")\n}\n";
        assert_eq!(native_main_stdout(src, "isotrail").trim(), "false|false|false|true|false|true");
    }

    /// A REAL BUG found+fixed (bug-hunt batch 168, PR-it560, found via an Explore-agent
    /// survey of datetime [this] vs encoding [confirmed a faithful, already-well-tested
    /// mirror -- no divergence found]): native's `k_parse_iso` used plain `strtol` for
    /// every numeric field (year/month/day/hour/minute/second), which silently CLAMPS an
    /// out-of-range numeral to `LONG_MIN`/`LONG_MAX` and still reports success (`*end`
    /// unchanged) -- unlike Rust's `i64::parse()` (time.rs's reference), which always
    /// rejects a numeral that doesn't fit. Month/day/hour/minute/second all get an
    /// EXPLICIT range check afterward (e.g. `mo < 1 || mo > 12`) that incidentally also
    /// catches a clamped LONG_MAX/LONG_MIN, but the YEAR field has no such check anywhere
    /// in `k_parse_iso` -- confirmed via a real 3-engine CLI probe that
    /// `parse_iso("99999999999999999999-01-01")` (a 20-digit year) correctly returned
    /// `Err(...)` on interp/vm but silently `Ok(-62198793216)` (a clamped, nonsensical
    /// epoch) on native. Fixed with a new `k_strtol_checked` helper (checks
    /// `errno == ERANGE` after `strtol`, matching `i64::parse()`'s stricter contract)
    /// applied to ALL SIX numeric fields for consistency, not just the year.
    #[test]
    fn native_parse_iso_rejects_strtol_overflow_in_every_field() {
        if !cc_available() {
            return;
        }
        let src = "fun main() uses io {\n    \
                   print(\"{parse_iso(\"99999999999999999999-01-01\").is_ok()}|\
                   {parse_iso(\"2024-99999999999999999999-01\").is_ok()}|\
                   {parse_iso(\"2024-01-99999999999999999999\").is_ok()}|\
                   {parse_iso(\"2024-01-01T99999999999999999999:00:00\").is_ok()}|\
                   {parse_iso(\"2024-01-01T00:99999999999999999999:00\").is_ok()}|\
                   {parse_iso(\"2024-01-01T00:00:99999999999999999999\").is_ok()}|\
                   {parse_iso(\"-100-01-01\").is_ok()}|{parse_iso(\"2024-01-01\").is_ok()}\")\n}\n";
        assert_eq!(
            native_main_stdout(src, "isooverflow").trim(),
            "false|false|false|false|false|false|true|true"
        );
    }

    /// A REAL cross-engine DIVERGENCE found+fixed (production-hardening
    /// PR-it959, found via a background survey's close-read of `k_parse_iso`
    /// noticing the `d`/`ss` fields have an explicit `[0] == 0` empty-
    /// substring guard that `y`/`hh`/`mi` lack): `k_strtol_checked` wraps
    /// plain C `strtol`, which treats an EMPTY string as a successful parse
    /// of `0` rather than an error, unlike Rust's `str::parse::<i64>()`
    /// (used uniformly for every field by `time.rs::parse_iso`, the shared
    /// interp/vm implementation, which always rejects an empty numeral
    /// cleanly). `mo` (month) is accidentally protected already -- a
    /// doubled dash makes `mstr` empty, `mo` parses to `0`, and the very
    /// next line's own `mo < 1` range check catches it downstream -- but
    /// `y`/`hh`/`mi` have no such accidental catch, since `0` is a
    /// legitimate year, hour, and minute. Confirmed live BEFORE this fix:
    /// a doubled leading dash on the year (`"--03-15"`, e.g. from string-
    /// concatenation building a negative-year date) or a doubled `:` on the
    /// hour/minute (`"...T:30:00"`, `"...T05::00"`) silently fabricated a
    /// bogus year-0000/midnight-hour/on-the-hour timestamp on native
    /// (`Ok`), while `kupl run`/`kupl run --vm` correctly agreed on `Err`
    /// for the identical input -- a genuine 3-way cross-engine divergence,
    /// not just a shared wrong answer. Fixed by mirroring `d`/`ss`'s own
    /// established `[0] == 0` empty-substring guard onto `y`/`hh`/`mi`.
    /// The well-formed negative-year shape (`"-0007-03-15"`) and
    /// legitimate zero-valued fields (`"0000-01-01"`, `"...T00:00:00"`)
    /// are confirmed to stay unaffected, live-verified across all three
    /// engines before this fix was finalized.
    #[test]
    fn native_parse_iso_rejects_a_doubled_separator_that_would_empty_a_numeral_field() {
        if !cc_available() {
            return;
        }
        let src = "fun main() uses io {\n    \
                   print(\"{parse_iso(\"--03-15\").is_ok()}|\
                   {parse_iso(\"2001-01-01T:30:00\").is_ok()}|\
                   {parse_iso(\"2001-01-01T05::00\").is_ok()}|\
                   {parse_iso(\"-0007-03-15\").is_ok()}|\
                   {parse_iso(\"0000-01-01\").is_ok()}|\
                   {parse_iso(\"2001-01-01T00:00:00\").is_ok()}\")\n}\n";
        assert_eq!(
            native_main_stdout(src, "isoemptynumeral").trim(),
            "false|false|false|true|true|true"
        );
    }

    /// A REAL cross-engine DIVERGENCE found+fixed (production-hardening
    /// PR-it1071, an Explore survey finding, independently re-verified live
    /// before implementing): `k_strtol_checked` wraps plain C `strtol`,
    /// which silently SKIPS leading whitespace, unlike Rust's `str::parse::
    /// <i64>()` (used uniformly for every numeral field by
    /// `time.rs::parse_iso`, the shared interp/vm implementation), which
    /// strictly rejects ANY embedded whitespace. None of `k_parse_iso`'s six
    /// call sites' own guards caught this -- the `*end` check passes since
    /// the parse genuinely succeeds, and the `[0]==0` empty-substring guards
    /// (PR-it959, the test just above) only catch a truly EMPTY field, not
    /// one that's merely whitespace-prefixed. A space landing AFTER the
    /// `T`/space date-time separator has already been consumed (so it's
    /// just part of an hour/minute/second digit string, not the separator
    /// itself) or a tab/CR/etc. anywhere within a field (never treated
    /// specially by the separator-detection loop, which only recognizes
    /// literal `T`/space) both silently fabricated a plausible-but-wrong
    /// timestamp on native, where interp/vm correctly returned `Err`. This
    /// is the SAME `strtol`/`strtoll` leading-whitespace hazard this file
    /// already guards against for the unrelated `parse_int`/`parse_radix`
    /// builtins -- that guard was never applied to `k_strtol_checked`.
    /// Fixed by adding the identical character-class check directly in the
    /// shared helper, covering all six numeral fields (year/month/day/
    /// hour/minute/second) with one change. The legitimate WHOLE-STRING
    /// Unicode-aware trim (`k_utf8_trim_range`, PR-it666, tested just below)
    /// is unaffected -- confirmed a leading tab before the entire timestamp
    /// still correctly parses (trimmed away before field-splitting even
    /// starts), only an internal, per-field leading whitespace character is
    /// newly rejected.
    #[test]
    fn native_parse_iso_rejects_whitespace_prefixed_numeral_fields_strtol_would_silently_skip() {
        if !cc_available() {
            return;
        }
        let src = "fun main() uses io {\n    \
                   print(\"{parse_iso(\"2024-01-01T 1:02:03\").is_ok()}|\
                   {parse_iso(\"2024-\\t1-01T00:00:00\").is_ok()}|\
                   {parse_iso(\"2024-01-\\t1T00:00:00\").is_ok()}|\
                   {parse_iso(\"\\t2024-01-01T00:00:00\").is_ok()}|\
                   {parse_iso(\"2024-01-01T00:00:00\").is_ok()}\")\n}\n";
        // BEFORE the fix, native printed "true|true|true|true|true" for the
        // first three (whitespace-prefixed field, silently accepted) while
        // interp/vm printed "false|false|false|true|true" (rejected, except
        // the legitimate whole-string leading tab, which both correctly
        // accept via the separate whole-string trim).
        assert_eq!(
            native_main_stdout(src, "isowsnumeral").trim(),
            "false|false|false|true|true"
        );
    }

    /// A REAL cross-engine DIVERGENCE found+fixed (production-hardening
    /// PR-it660, found while auditing shared modules for it658's "byte-
    /// identical wrong answer" blind spot -- this turned out to be a
    /// genuine DIVERGENCE instead, an even higher-severity find since it
    /// violates cross-engine byte-identity directly): `time.rs::parse_iso`
    /// does `s.trim().trim_end_matches('Z')`, which strips trailing `Z`
    /// characters REPEATEDLY (Rust's `trim_end_matches` loops until the
    /// pattern no longer matches) -- interp.rs and vm.rs both call this SAME
    /// shared function, so they necessarily agree. `k_parse_iso`'s C mirror
    /// used to strip only ONE trailing `Z` via a plain `if`, so an input
    /// with two-or-more trailing `Z`s parsed successfully (`Ok`) on
    /// interp/vm but failed (`Err`) on native alone -- confirmed live via
    /// `kupl run` vs `kupl native` on the same source before fixing.
    #[test]
    fn native_parse_iso_strips_every_trailing_z_not_just_one() {
        if !cc_available() {
            return;
        }
        let src = "fun main() uses io {\n    \
                   let zz = match parse_iso(\"2001-09-09T01:46:40ZZ\") { Ok(t) => \"{t}\", Err(m) => m }\n    \
                   print(\"{parse_iso(\"2001-09-09T01:46:40Z\").is_ok()}|\
                   {parse_iso(\"2001-09-09T01:46:40ZZ\").is_ok()}|\
                   {parse_iso(\"2001-09-09T01:46:40ZZZ\").is_ok()}|{zz}\")\n}\n";
        // BEFORE the fix, native printed "true|false|false|..." (only a
        // single Z stripped) while interp/vm printed "true|true|true|...".
        assert_eq!(
            native_main_stdout(src, "isozz").trim(),
            "true|true|true|1000000000"
        );
    }

    /// A REAL cross-engine DIVERGENCE found+fixed (production-hardening
    /// PR-it666, the SAME bug class as it662-665, and a SIBLING gap in the
    /// exact function it660 already fixed once): `time.rs::parse_iso`'s
    /// `s.trim()` is Rust's Unicode-aware trim, but `k_parse_iso`'s
    /// leading/trailing whitespace walk (separate from the trailing-`Z`
    /// loop it660 fixed) recognized ASCII space/tab/CR/LF only -- so a
    /// timestamp padded with a non-ASCII whitespace character (NBSP here)
    /// parsed successfully on interp/vm but failed on native alone;
    /// confirmed live via `parse_iso("\u{A0}2001-09-09T01:46:40Z\u{A0}")`
    /// BEFORE fixing (native returned `Err`, interp/vm returned `Ok`).
    #[test]
    fn native_parse_iso_trims_unicode_whitespace() {
        if !cc_available() {
            return;
        }
        let src = "fun main() uses io {\n    \
                   print(\"{parse_iso(\"\u{A0}2001-09-09T01:46:40Z\u{A0}\").is_ok()}|\
                   {parse_iso(\"2001-09-09T01:46:40Z\").is_ok()}\")\n}\n";
        assert_eq!(native_main_stdout(src, "isounicodetrim").trim(), "true|true");
    }

    /// Native's mock tool-calling loop matches interp/KVM: a multi-step loop reaches
    /// the final answer, and a no-final script is bounded by MAX_TOOL_ROUNDS (8) with
    /// the same message the interpreter uses (PR-it110 aligned native's boundary).
    #[test]
    fn native_ai_tool_loop_bound_matches_interp() {
        if !cc_available() {
            return;
        }
        let src = "fun add(a: Int, b: Int) -> Int { a + b }\n\
                   ai fun assist(q: Str) -> Str tools [add] {\n    intent \"Answer using tools.\"\n}\n\
                   fun main() uses io { print(assist(\"q\")) }\n";
        let compiled = crate::run::compile(src).expect("compiles");
        let module = crate::compile::compile_module(&compiled.program, &compiled.checked).expect("module");
        let c = super::emit_c(&module).expect("emit_c");
        let base = std::env::temp_dir().join(format!("kupl-ailoop-{}", std::process::id()));
        let cpath = base.with_extension("c");
        let bin = base.with_extension("out");
        std::fs::write(&cpath, &c).unwrap();
        assert!(std::process::Command::new(cc())
            .args(["-O2", "-o", bin.to_str().unwrap(), cpath.to_str().unwrap()])
            .status().unwrap().success());
        let _ = std::fs::remove_file(&cpath);
        let run = |mock: &str| -> (String, String) {
            let out = std::process::Command::new(&bin).env("KUPL_AI_MOCK_ASSIST", mock).output().unwrap();
            (String::from_utf8_lossy(&out.stdout).trim().to_string(), String::from_utf8_lossy(&out.stderr).to_string())
        };
        // multi-step loop reaches the final answer
        assert_eq!(run("[{\"tool\":\"add\",\"input\":{\"a\":2,\"b\":3}},{\"final\":\"done\"}]").0, "done");
        // a short no-final script exhausts; >= 8 rounds hits the round cap (same as interp)
        let seven = "[".to_string() + &vec!["{\"tool\":\"add\",\"input\":{\"a\":1,\"b\":1}}"; 7].join(",") + "]";
        assert!(run(&seven).1.contains("mock provider ran out of scripted rounds"), "7 rounds should exhaust");
        let ten = "[".to_string() + &vec!["{\"tool\":\"add\",\"input\":{\"a\":1,\"b\":1}}"; 10].join(",") + "]";
        assert!(run(&ten).1.contains("tool loop exceeded 8 rounds without a final answer"), "10 rounds should hit the cap");
        let _ = std::fs::remove_file(&bin);
    }

