    /// Native end-to-end integration: an ADT command, a Stock contract fulfilled by a
    /// stateful component with Map state, a method returning Result matched by the caller,
    /// collection HOFs — the composition runs identically to interp/KVM (PR-it133,
    /// examples/inventory.kupl). Feature-interaction regression guard.
    #[test]
    fn native_inventory_integration() {
        if !cc_available() {
            return;
        }
        let src = "type Cmd = Add(name: Str, n: Int) | Remove(name: Str, n: Int)\n\
                   contract Stock {\n    intent \"s\"\n    expose fun apply(c: Cmd) -> Result[Int, Str]\n}\n\
                   component Warehouse fulfills Stock {\n    intent \"w\"\n    state levels: Map[Str, Int] = Map()\n    \
                   expose fun apply(c: Cmd) -> Result[Int, Str] {\n        match c {\n            \
                   Add(name, n) => {\n                let cur = levels.get_or(name, 0)\n                levels = levels.insert(name, cur + n)\n                Ok(cur + n)\n            }\n            \
                   Remove(name, n) => {\n                let cur = levels.get_or(name, 0)\n                if n > cur { Err(\"short {name}\") } else {\n                    levels = levels.insert(name, cur - n)\n                    Ok(cur - n)\n                }\n            }\n        }\n    }\n    \
                   expose fun total() -> Int { levels.values().fold(0, fn(a, x) { a + x }) }\n}\n\
                   fun main() uses io {\n    let wh = Warehouse()\n    var out: List[Str] = []\n    \
                   for c in [Add(\"a\", 5), Remove(\"a\", 2), Remove(\"a\", 9), Add(\"b\", 3)] {\n        \
                   match wh.apply(c) {\n            Ok(v) => { out = out.push(\"ok {v}\") }\n            Err(e) => { out = out.push(e) }\n        }\n    }\n    \
                   print(\"{out.join(\" | \")} :: total {wh.total()}\")\n}\n";
        assert_eq!(
            native_main_stdout(src, "inventory").trim(),
            "ok 5 | ok 3 | short a | ok 3 :: total 6"
        );
    }

    /// Native contract dispatch: a function taking a contract-typed parameter calls the
    /// right component's method (polymorphism over `fulfills`), matching interp/KVM (PR-it129).
    #[test]
    fn native_contract_polymorphic_dispatch() {
        if !cc_available() {
            return;
        }
        let src = "contract Greeter {\n    intent \"g\"\n    expose fun greet(name: Str) -> Str\n}\n\
                   component Formal fulfills Greeter {\n    intent \"f\"\n    expose fun greet(name: Str) -> Str { \"Good day, {name}.\" }\n}\n\
                   component Casual fulfills Greeter {\n    intent \"c\"\n    expose fun greet(name: Str) -> Str { \"hey {name}\" }\n}\n\
                   fun welcome(g: Greeter, who: Str) -> Str { g.greet(who) }\n\
                   fun main() uses io {\n    print(\"{welcome(Formal(), \"Ada\")}|{welcome(Casual(), \"Bob\")}\")\n}\n";
        assert_eq!(native_main_stdout(src, "contractdisp").trim(), "Good day, Ada.|hey Bob");
    }

    /// Contract-assignability (component fulfilling a contract -> the contract
    /// type) used to only be checked at 4 sites (component props, initial let/var
    /// binding, positional/method call args); reassigning a contract-typed `var`
    /// to a DIFFERENT fulfilling component, a function's tail-expression return, a
    /// component `state` field annotated with a contract type, and a record/ADT
    /// field (both at construction and via `with`) typed as a contract were all
    /// wrongly rejected at compile time (PR-it565, fixed in the shared checker so
    /// this exercises native codegen for patterns it had never compiled before --
    /// a contract-typed state field, and constructing/`with`-updating a
    /// contract-typed record field).
    #[test]
    fn native_contract_assignable_beyond_component_props_and_call_args() {
        if !cc_available() {
            return;
        }
        let src = "contract Store {\n    intent \"kv\"\n    expose fun get() -> Int\n}\n\
                   component Mem fulfills Store {\n    intent \"mem\"\n    expose fun get() -> Int { 1 }\n}\n\
                   component Prefix fulfills Store {\n    intent \"prefix\"\n    expose fun get() -> Int { 2 }\n}\n\
                   component Holder {\n    intent \"h\"\n    state inner: Store = Mem()\n    expose fun peek() -> Int { inner.get() }\n}\n\
                   type Box = B(g: Store)\n\
                   fun mk() -> Store { Mem() }\n\
                   fun main() uses io {\n    \
                   var v: Store = Mem()\n    let r1 = v.get()\n    v = Prefix()\n    let r2 = v.get()\n    \
                   let h = Holder()\n    let r3 = h.peek()\n    let r4 = mk().get()\n    \
                   let b = B(g: Mem())\n    let b2 = b with g: Prefix()\n    \
                   let r5 = match b { B(g) => g.get() }\n    let r6 = match b2 { B(g) => g.get() }\n    \
                   print(\"{r1}|{r2}|{r3}|{r4}|{r5}|{r6}\")\n}\n";
        assert_eq!(native_main_stdout(src, "contractassign").trim(), "1|2|1|1|1|2");
    }

    /// `if`/`else` and `match` arms are SYMMETRIC merges -- neither branch is
    /// pre-typed as a contract, so `if b { Mem() } else { Prefix() }` needed a
    /// different check than it565's directional `check_assign` sites: do the two
    /// branch types share exactly ONE `fulfills` contract? Exercises native
    /// codegen for a 3-way `match` merge too, proving the widened contract type
    /// threads correctly past the first arm (PR-it566, `check_merge`/
    /// `common_fulfilled_contract` in check.rs).
    #[test]
    fn native_contract_branch_merge_widens_to_the_one_shared_fulfilled_contract() {
        if !cc_available() {
            return;
        }
        let src = "contract Store {\n    intent \"kv\"\n    expose fun get() -> Int\n}\n\
                   component Mem fulfills Store {\n    intent \"mem\"\n    expose fun get() -> Int { 1 }\n}\n\
                   component Prefix fulfills Store {\n    intent \"prefix\"\n    expose fun get() -> Int { 2 }\n}\n\
                   component Cached fulfills Store {\n    intent \"cache\"\n    expose fun get() -> Int { 3 }\n}\n\
                   fun mk_if(b: Bool) -> Store {\n    if b { Mem() } else { Prefix() }\n}\n\
                   fun mk_match(n: Int) -> Store {\n    match n {\n        0 => Mem()\n        1 => Prefix()\n        _ => Cached()\n    }\n}\n\
                   fun main() uses io {\n    \
                   print(\"{mk_if(true).get()}|{mk_if(false).get()}|{mk_match(0).get()}|{mk_match(1).get()}|{mk_match(2).get()}\")\n}\n";
        assert_eq!(
            native_main_stdout(src, "contractmerge").trim(),
            "1|2|1|2|3"
        );
    }

    /// List-literal element unification has the same fold-style-accumulator
    /// shape as match-arm merging -- `[Mem(), Prefix(), Cached()]` (all
    /// fulfilling one contract) used to reject with a bare K0200 since no
    /// element is pre-typed as the contract; now widens to `List[Store]`
    /// (PR-it567, same `check_merge` mechanism as it566's branch merging,
    /// applied to `ExprKind::List`'s accumulator).
    #[test]
    fn native_contract_list_literal_widens_to_the_one_shared_fulfilled_contract() {
        if !cc_available() {
            return;
        }
        let src = "contract Store {\n    intent \"kv\"\n    expose fun get() -> Int\n}\n\
                   component Mem fulfills Store {\n    intent \"mem\"\n    expose fun get() -> Int { 1 }\n}\n\
                   component Prefix fulfills Store {\n    intent \"prefix\"\n    expose fun get() -> Int { 2 }\n}\n\
                   component Cached fulfills Store {\n    intent \"cache\"\n    expose fun get() -> Int { 3 }\n}\n\
                   fun main() uses io {\n    \
                   let gs: List[Store] = [Mem(), Prefix(), Cached()]\n    \
                   var out = \"\"\n    \
                   for g in gs {\n        out = out + \"{g.get()}\"\n    }\n    \
                   print(out)\n}\n";
        assert_eq!(native_main_stdout(src, "contractlist").trim(), "123");
    }

    /// Native if-let (expression + nested pattern) and while-let (termination) match
    /// interp/KVM (PR-it125).
    #[test]
    fn native_if_let_and_while_let() {
        if !cc_available() {
            return;
        }
        let src = "type Pt = Pt(x: Int, y: Int)\nfun step(n: Int) -> Option[Int] { if n > 0 { Some(n * n) } else { None } }\n\
                   fun main() uses io {\n    let a: Option[Int] = Some(7)\n    let p: Option[Pt] = Some(Pt(3, 4))\n    \
                   var n = 3\n    var acc: List[Int] = []\n    while let Some(sq) = step(n) {\n        acc = acc.push(sq)\n        n = n - 1\n    }\n    \
                   print(\"{if let Some(x) = a { x * 2 } else { 0 }}|{if let Some(Pt(x, y)) = p { x + y } else { 0 }}|{acc}\")\n}\n";
        assert_eq!(native_main_stdout(src, "iflet").trim(), "14|7|[9, 4, 1]");
    }

