    /// The native mirror of `diff_bigint_divmod_multi_limb_and_dividend_smaller_than_divisor`
    /// (vm.rs, PR-it717): `native_bigint_and_rational_match` above only ever
    /// exercises SINGLE-limb BigInt division (`17 / 5`); `k_big_divmod`'s
    /// binary-search-based long-division algorithm (the independent C
    /// reimplementation of `bigint.rs`'s `divmod_mag`, PR-it709's highest-
    /// risk-site lesson) had no genuine MULTI-limb coverage on the native
    /// side either. Same cases as the interp/KVM differential test, cross-
    /// checked against Python's arbitrary-precision arithmetic as ground
    /// truth before this test was written -- confirmed clean, locked in here.
    #[test]
    fn native_bigint_divmod_multi_limb_and_dividend_smaller_than_divisor() {
        if !cc_available() {
            return;
        }
        let src = "fun main() uses io {\n    \
                   let a = big(\"123456789012345678901234567890\")\n    \
                   let b = big(\"987654321098765432109876543\")\n    \
                   let c = big(\"-123456789012345678901234567890\")\n    \
                   let d = big(\"42\")\n    \
                   let e = big(\"123456789012345678901234567890\")\n    \
                   let f = big(\"999999999999999999999999999999999999999\")\n    \
                   let g = big(\"1000000000000000000\")\n    \
                   let h = big(\"999999999\")\n    \
                   print(\"{a / b}|{a % b}|{c / b}|{c % b}|{a / (-b)}|{a % (-b)}|{d / e}|{d % e}|{f / f}|{f % f}|{g / h}|{g % h}\")\n}\n";
        assert_eq!(
            native_main_stdout(src, "bigdivmod").trim(),
            "124|987653196098765319609876558|\
             -124|-987653196098765319609876558|\
             -124|987653196098765319609876558|\
             0|42|\
             1|0|\
             1000000001|1"
        );
    }

    /// The native mirror of `diff_rational_construction_and_comparison_reject_a_gcd_or_multiply_too_large_to_compute`
    /// (vm.rs, PR-it718): `k_rat_norm`'s `k_big_gcd` call and `k_rat_cmp`'s
    /// cross-multiplication are BOTH independent C reimplementations of the
    /// SAME uncapped-building-block pattern `rational.rs`'s `Rational::new`/
    /// `cmp` have -- confirmed live BEFORE this fix that native hung
    /// identically to interp/KVM on both the huge/huge construction case AND
    /// the asymmetric-comparison case (and, distinctly, that native's `k_eq`
    /// used to route `==` through the SAME expensive `k_rat_cmp` where
    /// interp.rs's cheap structural `PartialEq` never pays that cost at all
    /// -- a genuine cross-engine behavioral gap fixed alongside the DoS,
    /// not just a performance one).
    #[test]
    fn native_rational_gcd_and_comparison_reject_a_computation_too_large_to_attempt() {
        assert_panic_wording_matches(
            "fun main() uses io {\n    let s = \"9\".repeat(1000)\n    print(\"{rat(big(s), big(s))}\")\n}\n",
            "ratctorcap",
        );
        assert_panic_wording_matches(
            "fun main() uses io {\n    let s = \"9\".repeat(180000)\n    \
             let r1 = rat(big(s), 3)\n    let r2 = rat(3, big(s))\n    print(\"{r1 < r2}\")\n}\n",
            "ratcmpcap",
        );
        if !cc_available() {
            return;
        }
        // ONE huge operand paired with a small one constructs/compares fine.
        let ok = "fun main() uses io {\n    let s = \"9\".repeat(1000)\n    print(\"{rat(big(s), 3) > rat(1, 1)}\")\n}\n";
        assert_eq!(native_main_stdout(ok, "ratctorok").trim(), "true");
        // == uses cheap structural comparison, NOT k_rat_cmp -- must stay
        // fast and correct even for the same asymmetric huge/tiny shape.
        let eq_check = "fun main() uses io {\n    let s = \"9\".repeat(1000)\n    \
                        print(\"{rat(big(s), 3) == rat(big(s), 3)}\")\n}\n";
        assert_eq!(native_main_stdout(eq_check, "rateq").trim(), "true");
    }

    /// A REAL bug found+fixed (production-hardening PR-it1000, a close-read
    /// survey of cgen.rs's BigInt/Rational builtins): `k_big_builtin`'s and
    /// `k_rat_to_big`'s type-mismatch panics dropped the offending type
    /// name entirely, unlike `interp.rs`'s `big_builtin`/`rat_builtin`
    /// (`"...found {}", other.type_name()`). Reachable from valid,
    /// check.rs-accepted source: `check.rs`'s `("big", 1)`/`("rat", 2)`
    /// signature entries never `unify` their argument against `Int`/`Str`/
    /// `BigInt`, so a mistyped argument only fails at THIS runtime panic.
    /// Live-confirmed before this fix: interp/KVM said `` `big` needs an
    /// Int or a Str, found Bool `` while native said only `` `big` needs
    /// an Int or a Str ``. Fixed by reusing the existing `k_type_name`
    /// helper (a forward declaration was needed since both call sites
    /// precede its own definition).
    #[test]
    fn native_big_and_rat_type_mismatch_panic_names_the_offending_type() {
        assert_panic_wording_matches("fun main() uses io {\n    print(big(true))\n}\n", "bigwording");
        assert_panic_wording_matches("fun main() uses io {\n    print(rat(true, 3))\n}\n", "ratwording");
    }

    /// A REAL bug found+fixed (production-hardening PR-it943, the SAME
    /// class as PR-it639's operator-boundary fix): `k_add`/`k_sub`/`k_mul`/
    /// `k_div` each call `k_big_check_size`/`k_rat_check_size` after
    /// computing, but `List.sum()`/`.product()`'s own BigInt/Rational
    /// accumulator loops called `k_big_add`/`k_big_mul`/`k_rat_add`/
    /// `k_rat_mul` DIRECTLY, bypassing that check entirely -- confirmed
    /// live BEFORE this fix that `[a, a, a].product()` (three copies of an
    /// individually-legal, near-cap BigInt) silently produced a result 3x
    /// past the documented cap on native, exactly matching interp/KVM's own
    /// (also pre-fix) identical gap -- this is an INDEPENDENT gap in
    /// native's own reimplementation, not merely inherited: native never
    /// called the check here either, confirmed by direct code read.
    #[test]
    fn native_bigint_sum_and_product_reject_growth_past_the_cap() {
        assert_panic_wording_matches(
            "fun main() uses io {\n    let a = big(\"9\".repeat(180000))\n    \
             let xs = [a, a, a]\n    print(\"{xs.product()}\")\n}\n",
            "bigsumprodcap1",
        );
        assert_panic_wording_matches(
            "fun main() uses io {\n    let a = big(\"9\".repeat(180000))\n    \
             let xs = [a, a]\n    print(\"{xs.sum()}\")\n}\n",
            "bigsumprodcap2",
        );
        if !cc_available() {
            return;
        }
        // ordinary, legitimate sum/product is completely unaffected.
        let ok = "fun main() uses io {\n    let xs = [big(2), big(3), big(4)]\n    \
                  print(\"{xs.sum()},{xs.product()}\")\n}\n";
        assert_eq!(native_main_stdout(ok, "bigsumprodok").trim(), "9,24");
    }

